def validate_rdec(rdec, known_decisions):
    # C-TOTALITY: ensure rdec is a dict
    if not isinstance(rdec, dict):
        return {"ok": False, "problems": ["rdec must be a dict"]}

    # Define required fields
    required_fields = ["rdec_id", "decision", "axis", "why_required", "expected_decision_effect", "omission_risk", "stop_condition_ref"]

    # C1: Check all listed fields are present
    problems = []
    missing_fields = [field for field in required_fields if field not in rdec]
    if missing_fields:
        return {"ok": False, "problems": [f"missing required fields: {missing_fields}"]}

    # C2: decision must be in known_decisions
    if rdec["decision"] not in known_decisions:
        return {"ok": False, "problems": ["decision must be in known_decisions"]}

    # C3: expected_decision_effect must be non-empty string
    expected_effect = rdec["expected_decision_effect"]
    if not isinstance(expected_effect, str) or expected_effect.strip() == "":
        return {"ok": False, "problems": ["expected_decision_effect must be a non-empty string"]}

    # C4: omission_risk must be non-empty
    omission_risk = rdec["omission_risk"]
    if not isinstance(omission_risk, str) or omission_risk.strip() == "":
        return {"ok": False, "problems": ["omission_risk must be a non-empty string"]}

    # C5: stop_condition_ref must be non-empty
    stop_condition_ref = rdec["stop_condition_ref"]
    if not isinstance(stop_condition_ref, str) or stop_condition_ref.strip() == "":
        return {"ok": False, "problems": ["stop_condition_ref must be a non-empty string"]}

    # All checks passed
    return {"ok": True, "problems": []}
